import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "1 OR 1=1";

            // Establishing a connection to the database
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Constructing a parameterized query using PreparedStatement
            String query = "SELECT * FROM users WHERE id=?";
            PreparedStatement preparedStatement = connection.prepareStatement(query);

            // Setting the user input as a parameter in the prepared statement
            preparedStatement.setString(1, userInput);

            // Executing the query using the prepared statement
            ResultSet resultSet = preparedStatement.executeQuery();

            // Processing the results
            while(resultSet.next()) {
                System.out.println("User ID: " + resultSet.getInt("id") + ", Username: " + resultSet.getString("username"));
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

